{"changed":true,"filter":false,"title":"freez.php","tooltip":"/freez.php","value":"<?php\n// 假设数据库连接已建立，并存储在变量 $conn 中\n$sql = \"SELECT product_id, product_name, unit_price, unit_quantity, in_stock FROM products WHERE product_id BETWEEN 1 AND 10\";\n$result = $conn->query($sql);\n?>\n<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n    <meta charset=\"UTF-8\">\n    <title>Freeze Page</title>\n    <style>\n        /* 基础样式 */\n        body {\n            margin: 0;\n            padding: 0;\n            font-family: Arial, sans-serif;\n        }\n        /* 顶部区域：搜索框、Logo、购物车/个人图标 */\n        header {\n            background-color: #f2f2f2;\n            display: flex;\n            align-items: center;\n            padding: 10px 20px;\n        }\n        .search-container {\n            flex: 1;\n        }\n        .search-container input[type=\"text\"] {\n            width: 100%;\n            padding: 8px;\n            box-sizing: border-box;\n        }\n        .logo {\n            margin: 0 20px;\n        }\n        .logo img {\n            height: 50px;\n            width: auto;\n            transition: transform 0.3s ease;\n        }\n        .logo img:hover {\n            transform: scale(1.1);\n        }\n        .user-cart {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n        }\n        .user-cart span {\n            cursor: pointer;\n            transition: transform 0.3s ease;\n        }\n        .user-cart span:hover {\n            transform: scale(1.1);\n        }\n        \n        /* 导航栏样式 */\n        nav {\n            background-color: #e6e6e6;\n            padding: 10px 20px;\n        }\n        nav ul {\n            margin: 0;\n            padding: 0;\n            list-style: none;\n            display: flex;\n            gap: 20px;\n            justify-content: center;\n        }\n        nav li {\n            position: relative;\n            cursor: pointer;\n            transition: color 0.3s ease, transform 0.3s ease;\n        }\n        nav li:hover {\n            color: #007BFF;\n            transform: scale(1.1);\n        }\n        /* 下拉菜单样式 */\n        .dropdown-menu {\n            display: none;\n            position: absolute;\n            top: 100%;\n            left: 0;\n            background: #fff;\n            padding: 10px 0;\n            box-shadow: 0 2px 8px rgba(0,0,0,0.15);\n            min-width: 150px;\n            z-index: 1000;\n        }\n        .dropdown-menu li {\n            padding: 8px 20px;\n            white-space: nowrap;\n            transition: background-color 0.3s ease;\n        }\n        .dropdown-menu li:hover {\n            background-color: #f2f2f2;\n        }\n        /* 鼠标悬停时显示下拉菜单 */\n        nav li:hover .dropdown-menu {\n            display: block;\n        }\n        \n        /* 主体商品网格样式：每行显示三个产品 */\n        .product-grid {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr);\n            gap: 20px;\n            padding: 20px;\n            box-sizing: border-box;\n            max-width: 1200px;\n            margin: 0 auto;\n        }\n        .product-item {\n            border: 1px solid #ccc;\n            padding: 10px;\n            text-align: center;\n            background-color: #fff;\n        }\n        .product-item img {\n            width: 200px;\n            height: 200px;\n            object-fit: cover;\n            margin-bottom: 10px;\n            transition: transform 0.3s ease;\n        }\n        .product-item img:hover {\n            transform: scale(1.05);\n        }\n        .product-item h3 {\n            font-size: 16px;\n            margin: 5px 0;\n        }\n        .product-item p {\n            margin: 5px 0;\n        }\n    </style>\n</head>\n<body>\n\n    <!-- 顶部搜索栏、Logo、购物车/个人图标 -->\n    <header>\n        <div class=\"search-container\">\n            <input type=\"text\" placeholder=\"Search for Anything\">\n        </div>\n        <div class=\"logo\">\n            <img src=\"logo_final.png\" alt=\"Normal Market Logo\">\n        </div>\n        <div class=\"user-cart\">\n            <span>🛒</span>\n            <span>👤</span>\n        </div>\n    </header>\n\n    <!-- 导航栏：Home, Freeze, Fresh, Drink, Pet, Household -->\n    <nav>\n        <ul>\n            <li>Home</li>\n            <li>\n                Freeze\n                <ul class=\"dropdown-menu\">\n                    <li>Fast Food</li>\n                    <li>Meat</li>\n                    <li>Fruits and Vegetables</li>\n                    <li>Ice Cream</li>\n                </ul>\n            </li>\n            <li>\n                Fresh\n                <ul class=\"dropdown-menu\">\n                    <li>Meat</li>\n                    <li>Vegetable</li>\n                    <li>Seafood</li>\n                    <li>Fruits</li>\n                    <li>spice</li>\n                </ul>\n            </li>\n            <li>\n                Drink\n                <ul class=\"dropdown-menu\">\n                    <li>Soft Drink</li>\n                    <li>water</li>\n                    <li>Dairy</li>\n                    <li>Alcohol</li>\n                </ul>\n            </li>\n            <li>\n                Pet\n                <ul class=\"dropdown-menu\">\n                    <li>Dog</li>\n                    <li>Cat</li>\n                    <li>Others</li>\n                </ul>\n            </li>\n            <li>\n                Household\n                <ul class=\"dropdown-menu\">\n                    <li>Kitchen</li>\n                    <li>Bathroom</li>\n                    <li>Electrical Equipment</li>\n                </ul>\n            </li>\n        </ul>\n    </nav>\n\n    <!-- 主体内容：产品网格 -->\n    <main>\n        <div class=\"product-grid\">\n            <?php\n            if ($result && $result->num_rows > 0) {\n                // 循环输出产品数据\n                while ($row = $result->fetch_assoc()) {\n                    // 根据产品名称生成图片文件名：将空格替换为下划线并加 .png\n                    $imgFile = str_replace(\" \", \"_\", $row[\"product_name\"]) . \".png\";\n                    echo '<div class=\"product-item\">';\n                    echo '<img src=\"' . htmlspecialchars($imgFile) . '\" alt=\"' . htmlspecialchars($row[\"product_name\"]) . '\">';\n                    echo '<h3>' . htmlspecialchars($row[\"product_name\"]) . '</h3>';\n                    // 显示价格和单位，例如 \"$40.00 1KG\"\n                    echo '<p>$' . number_format($row[\"unit_price\"], 2) . ' ' . htmlspecialchars($row[\"unit_quantity\"]) . '</p>';\n                    // 检测库存状态：in_stock 不为0显示 \"in stock\"，否则显示 \"out of stock\"\n                    echo '<p>' . (($row[\"in_stock\"] != 0) ? \"in stock\" : \"out of stock\") . '</p>';\n                    echo '</div>';\n                }\n            } else {\n                echo '<p style=\"text-align:center;\">No products found.</p>';\n            }\n            ?>\n        </div>\n    </main>\n\n</body>\n</html>\n","undoManager":{"mark":-2,"position":0,"stack":[[{"start":{"row":0,"column":0},"end":{"row":186,"column":0},"action":"remove","lines":["<!DOCTYPE html>","<html lang=\"en\">","<head>","    <meta charset=\"UTF-8\">","    <title>My Minimal Webpage</title>","    <style>","        /* 基础样式 */","        body {","            margin: 0;","            padding: 0;","            font-family: Arial, sans-serif;","        }","        header {","            background-color: #f2f2f2;","            display: flex;","            align-items: center;","            padding: 10px 20px;","        }","        .search-container {","            flex: 1;","        }","        .search-container input[type=\"text\"] {","            width: 100%;","            padding: 8px;","            box-sizing: border-box;","        }","        .logo {","            margin: 0 20px;","        }","        .logo img {","            height: 50px; /* 根据需要调整 */","            width: auto;","        }","        .user-cart {","            display